	private static CascadesCostModel model(RdfStatisticsProvider provider) {
		return new CascadesCostModel.DefaultCascadesCostModel(new EvaluationStatistics(), null, provider);
	}

	private static Winner profileWinner(int id, TupleExpr tupleExpr, BindingProfile profile) {
		MemoExpr expression = new MemoExpr(id, id, tupleExpr.getClass().getSimpleName(), List.of(), "test", tupleExpr,
				PhysicalProperties.builder().bindingProfile(profile).build(), RuleKind.IMPLEMENTATION, CostVector.ZERO,
				List.of(), "winner-" + id);
		return new Winner(expression, tupleExpr, PhysicalProperties.builder().bindingProfile(profile).build(),
				new CostVector(1.0d, 1.0d, 0.0d, 0.0d, 0.0d, 1.0d, 1.0d), List.of(), false, "");
	}

	private static BindingProfile finiteProfile(String variable, Value value) {
		FiniteRelationEstimate relation = FiniteRelationEstimate.fromRows(List.of(variable), List.of(List.of(value)),
				"test-finite-anchor");
		BagEstimate bag = BagEstimate.exact(1.0d, "test-finite-anchor")
				.withFiniteRelation(relation);
		return BindingProfile.fromBag(null, bag, Map.of());
	}

	private static Value iri(String value) {
		return SimpleValueFactory.getInstance().createIRI(value);
	}

	private static StatementPattern pattern(String subject, String predicate, String object) {
		return new StatementPattern(new Var(subject), new Var(predicate), new Var(object));
	}

	private static Winner winner(int groupId, TupleExpr plan) {
		return winner(groupId, plan, 0.0d);
	}

	private static Winner winner(int groupId, TupleExpr plan, double rows) {
		MemoExpr expression = new MemoExpr(groupId, groupId, plan.getClass().getSimpleName(), List.of(), "", plan,
				PhysicalProperties.ANY, RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of(), null);
		PhysicalProperties delivered = PhysicalProperties.builder()
				.boundVars(plan.getBindingNames())
				.build();
		CostVector cost = rows > 0.0d
				? CostVector.ofRowsAndWork(rows, rows, QErrorInterval.heuristic(rows, 4.0d, "test-winner"))
				: CostVector.ZERO;
		return new Winner(expression, plan, delivered, cost, List.of(), false, "");
	}

	private static final class TrackingProvider implements RdfStatisticsProvider {
		private int filterCalls;
		private int multiPatternCalls;
		private final List<Set<String>> rightPatternBoundVars = new ArrayList<>();
		private final boolean provideMultiPattern;
		private final double multiPatternRows;

		private TrackingProvider() {
			this(true);
		}

		private TrackingProvider(boolean provideMultiPattern) {
			this(provideMultiPattern, 7.0d);
		}

		private TrackingProvider(boolean provideMultiPattern, double multiPatternRows) {
			this.provideMultiPattern = provideMultiPattern;
			this.multiPatternRows = multiPatternRows;
		}

		@Override
		public Optional<StatisticsEstimate> statementPattern(StatementPattern pattern, Set<String> boundVars) {
			if ("right".equals(pattern.getPredicateVar().getName())) {
				rightPatternBoundVars.add(boundVars == null ? Set.of() : Set.copyOf(boundVars));
			}
			double rows = pattern.getPredicateVar().getName().equals("p1") ? 20.0d : 5.0d;
			return Optional.of(StatisticsEstimate.exact(rows, "test-statement"));
		}

		@Override
		public Optional<StatisticsEstimate> filter(TupleExpr input, ValueExpr condition,
				StatisticsEstimate inputEstimate, Set<String> boundVars) {
			filterCalls++;
			EstimateVector vector = inputEstimate.vector()
					.filter(0.10d,
							QErrorInterval.fromBounds(0.05d, 0.10d, 0.20d, 0.80d, "test-filter"),
							"test-filter");
			return Optional.of(StatisticsEstimate.fromVector(vector, "test-filter"));
		}

		@Override
		public Optional<StatisticsEstimate> multiPatternJoin(List<TupleExpr> orderedFactors, Set<String> boundVars) {
			multiPatternCalls++;
			if (!provideMultiPattern) {
				return Optional.empty();
			}
			return Optional.of(StatisticsEstimate.heuristic(multiPatternRows, "test-multi-pattern"));
		}
	}

	private static final class RecordingFactorCostModel implements JoinFactorCostModel {
		private final List<EstimationTier> estimationTiers = new ArrayList<>();
		private final double outputRows;

		private RecordingFactorCostModel() {
			this(1.0d);
		}

		private RecordingFactorCostModel(double outputRows) {
			this.outputRows = outputRows;
		}

		@Override
		public Optional<FactorCostEstimate> estimateFactorCost(TupleExpr factor, Set<String> currentlyBoundVars) {
			return Optional.empty();
		}

		@Override
		public Optional<FactorCostEstimate> estimateFactorCost(TupleExpr factor, CostContext context) {
			estimationTiers.add(context.getEstimationTier());
			return Optional.of(new FactorCostEstimate(outputRows * 2.0d, outputRows, Map.of(), Map.of()));
		}
	}
